#include <iostream>

class Point3D {
    int m_x, m_y, m_z;
public:
    Point3D(int x, int y, int z) : m_x{x}, m_y{y}, m_z{z} {}

    Point3D& operator=(const Point3D& rhs) {
        if (this == &rhs)
            return *this;
        m_x = rhs.m_x;
        m_y = rhs.m_y;
        m_z = rhs.m_z;
        return *this;
    }

    void print(char label) const {
        std::cout << label << ": " << m_x << ' ' << m_y << ' ' << m_z << '\n';
    }
};

int main() {
    int ax, ay, az, bx, by, bz, cx, cy, cz;
    std::cin >> ax >> ay >> az;
    std::cin >> bx >> by >> bz;
    std::cin >> cx >> cy >> cz;
    Point3D A{ax, ay, az};
    Point3D B{bx, by, bz};
    Point3D C{cx, cy, cz};
    A = B = C;
    A.print('A');
    B.print('B');
    return 0;
}

