#include <iostream>

class Counter {
    int m_count;
public:
    Counter(int c) : m_count{c} {}

    Counter& operator=(const Counter& rhs) {
        if (this == &rhs)
            return *this;
        m_count = rhs.m_count;
        return *this;
    }

    Counter operator-() const { return Counter{-m_count}; }
    int getValue() const { return m_count; }
};

int main() {
    int va, vb;
    std::cin >> va >> vb;
    Counter A{va};
    Counter B{vb};
    std::cout << "before: " << B.getValue() << '\n';
    A = B;
    std::cout << "after: "   << A.getValue() << '\n';
    Counter neg = -A;
    std::cout << "negated: " << neg.getValue() << '\n';
    return 0;
}
